function getSavedVocab() {
  try { return JSON.parse(localStorage.getItem('jimmy-li-saved-vocab')) || []; }
  catch { return []; }
}
function setSavedVocab(words) { localStorage.setItem('jimmy-li-saved-vocab', JSON.stringify(words)); }
function isSavedVocab(word) { return getSavedVocab().some(v => v.word === word); }
function getRandomGsatWords(count = 3, source = gsat7000Words) { return [...source].sort(() => Math.random() - 0.5).slice(0, count); }
function updateVocabStats() {
  const saved = getSavedVocab();
  const el = document.getElementById('vocabStats');
  if (!el) return;
  const mode = window.vocabMode || 'learn';
  el.innerHTML = [
    '<button class="vocab-stat' + (mode === 'review' ? ' active' : '') + '" type="button" data-vocab-mode="review">收藏 ' + saved.length + ' 字</button>',
    '<button class="vocab-stat' + (mode === 'learn' ? ' active' : '') + '" type="button" data-vocab-mode="learn">題庫 ' + gsat7000Words.length + ' 字</button>',
    '<button class="vocab-stat' + (mode === 'quiz' ? ' active' : '') + '" type="button" data-vocab-mode="quiz">模式 ' + (mode === 'review' ? '收藏複習' : mode === 'quiz' ? '小測驗' : '單字卡') + '</button>'
  ].join('');
}
function toggleSavedVocab(word) {
  const item = gsat7000Words.find(v => v.word === word);
  if (!item) return;
  const saved = getSavedVocab();
  const exists = saved.some(v => v.word === word);
  setSavedVocab(exists ? saved.filter(v => v.word !== word) : [item, ...saved]);
  updateEnglish();
  showToast(exists ? '已從收藏移除' : '已加入收藏複習');
}
function updateEnglish() {
  const mode = window.vocabMode || 'learn';
  const saved = getSavedVocab();
  const source = mode === 'review' ? saved : gsat7000Words;
  const words = getRandomGsatWords(3, source.length ? source : gsat7000Words);
  updateVocabStats();
  document.getElementById('englishText').textContent = mode === 'quiz' ? '學測 7000 單字小測驗' : mode === 'review' ? '收藏單字複習' : '學測 7000 隨機單字';
  document.getElementById('englishTrans').textContent = mode === 'quiz' ? '選出英文單字對應的中文意思，答錯也沒關係，立刻記住就賺到。' : mode === 'review' ? (saved.length ? '從你收藏的不熟單字中隨機抽出複習，適合睡前或通勤快速回想。' : '目前還沒有收藏單字，先在單字卡中按「收藏」建立自己的複習清單。') : '每次隨機抽 3 個核心單字，遇到不熟的字可以加入收藏複習。';
  if (mode === 'quiz') {
    const answer = words[0];
    window.currentQuizAnswer = answer.def;
    const options = [...words.map(v => v.def), ...getRandomGsatWords(3).map(v => v.def)].filter((value, index, arr) => arr.indexOf(value) === index).sort(() => Math.random() - 0.5).slice(0, 4);
    document.getElementById('englishVocab').innerHTML = ['<div class="english-word">','<div class="english-word-label">請選出意思</div>','<div class="english-word-def"><strong>' + escHtml(answer.word) + '</strong> <span class="english-word-pos">' + escHtml(answer.pos) + '</span></div>','<div class="english-word-example">' + escHtml(answer.example) + '</div>','<div class="quiz-options">' + options.map(option => '<button class="quiz-option" data-answer="' + escHtml(option) + '">' + escHtml(option) + '</button>').join('') + '</div>','</div>'].join('');
    return;
  }
  if (mode === 'review' && !saved.length) {
    document.getElementById('englishVocab').innerHTML = '<div class="english-word"><div class="english-word-label">收藏清單是空的</div><div class="english-word-def">先切回單字卡，把不熟的字加入收藏。</div></div>';
    return;
  }
  document.getElementById('englishVocab').innerHTML = words.map((v, index) => {
    const exists = isSavedVocab(v.word);
    return ['<div class="english-word">','<div class="english-word-label"><strong>' + (index + 1) + '. ' + escHtml(v.word) + '</strong> <span class="english-word-pos">' + escHtml(v.pos) + '</span></div>','<div class="english-word-def">' + escHtml(v.def) + '</div>','<div class="english-word-example">例句：' + escHtml(v.example) + '</div>','<div class="english-word-example">延伸：' + escHtml(v.related) + '</div>','<div class="vocab-actions"><button class="vocab-action' + (exists ? ' saved' : '') + '" type="button" data-save-word="' + escHtml(v.word) + '">' + (exists ? '已收藏' : '收藏') + '</button></div>','</div>'].join('');
  }).join('');
}
document.getElementById('englishRefresh').addEventListener('click', updateEnglish);
document.getElementById('vocabLearnMode').addEventListener('click', () => { window.vocabMode = 'learn'; document.querySelectorAll('.vocab-mode .mini-toggle').forEach(b => b.classList.remove('active')); document.getElementById('vocabLearnMode').classList.add('active'); updateEnglish(); });
document.getElementById('vocabQuizMode').addEventListener('click', () => { window.vocabMode = 'quiz'; document.querySelectorAll('.vocab-mode .mini-toggle').forEach(b => b.classList.remove('active')); document.getElementById('vocabQuizMode').classList.add('active'); updateEnglish(); });
document.getElementById('vocabReviewMode').addEventListener('click', () => { window.vocabMode = 'review'; document.querySelectorAll('.vocab-mode .mini-toggle').forEach(b => b.classList.remove('active')); document.getElementById('vocabReviewMode').classList.add('active'); updateEnglish(); });
updateEnglish();
