    ranges.forEach(input => {
      const subject = input.dataset.subjectProgress;
      input.value = subjectProgress[subject] ?? input.value;
      const label = input.closest('label')?.querySelector('span');
      if (label) label.textContent = subject + ' ' + input.value + '%';
    });
    const values = Object.entries(subjectProgress);
    const avg = values.length ? Math.round(values.reduce((sum, [, value]) => sum + Number(value), 0) / values.length) : 0;
