  let prevDays = -1, prevHours = -1, prevMinutes = -1, prevSeconds = -1;

  function animateFlip(el) {
    el.classList.remove('flip');
    void el.offsetWidth;
    el.classList.add('flip');
  }

  function updateExamCountdown() {
    const target = new Date(`${examDateInput.value || GSAT_START}T00:00:00+08:00`).getTime();
    const diff = target - Date.now();
    const safe = Math.max(diff, 0);

    const days    = Math.floor(safe / 86400000);
    const hours   = Math.floor((safe % 86400000) / 3600000);
    const minutes = Math.floor((safe % 3600000) / 60000);
    const seconds = Math.floor((safe % 60000) / 1000);

    const dEl = document.getElementById('countDays');
    const hEl = document.getElementById('countHours');
    const mEl = document.getElementById('countMinutes');
    const sEl = document.getElementById('countSeconds');

    if (days !== prevDays)    { dEl.textContent = String(days).padStart(3, '0');    animateFlip(document.getElementById('ci-days')); }
    if (hours !== prevHours)  { hEl.textContent = String(hours).padStart(2, '0');   animateFlip(document.getElementById('ci-hours')); }
    if (minutes !== prevMinutes) { mEl.textContent = String(minutes).padStart(2, '0'); animateFlip(document.getElementById('ci-minutes')); }
    if (seconds !== prevSeconds) { sEl.textContent = String(seconds).padStart(2, '0'); animateFlip(document.getElementById('ci-seconds')); }

    prevDays = days; prevHours = hours; prevMinutes = minutes; prevSeconds = seconds;

    const total = target - PREP_START;
    const elapsed = Date.now() - PREP_START;
    const pct = total > 0 ? Math.min(100, Math.max(0, (elapsed / total) * 100)) : 100;
    document.getElementById('progressFill').style.width = pct.toFixed(1) + '%';
    document.getElementById('progressPct').textContent =
      diff > 0 ? `\u5df2\u6e96\u5099 ${pct.toFixed(1)}%` : '\u5df2\u5230\u9054\u76ee\u6a19\u65e5\u671f';

    const msg = document.getElementById('countMessage');
    if (diff <= 0) {
      msg.classList.add('show');
    } else {
      msg.classList.remove('show');
    }
  }

