  // ── IndexedDB uploads ─────────────────────────────────────
  const uploadDbName = 'jimmy-li-learning-hub';
  const uploadStoreName = 'uploads';

  function openUploadDb() {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(uploadDbName, 1);
      request.onupgradeneeded = () => {
        const db = request.result;
        if (!db.objectStoreNames.contains(uploadStoreName))
          db.createObjectStore(uploadStoreName, { keyPath: 'id' });
      };
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }

  async function getUploads() {
    const db = await openUploadDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(uploadStoreName, 'readonly');
      const req = tx.objectStore(uploadStoreName).getAll();
      req.onsuccess = () => resolve(req.result || []);
      req.onerror = () => reject(req.error);
      tx.oncomplete = () => db.close();
    });
  }

  async function putUpload(record) {
    const db = await openUploadDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(uploadStoreName, 'readwrite');
      tx.objectStore(uploadStoreName).put(record);
      tx.oncomplete = () => { db.close(); resolve(); };
      tx.onerror = () => { db.close(); reject(tx.error); };
    });
  }

  async function deleteUpload(id) {
    const db = await openUploadDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(uploadStoreName, 'readwrite');
      tx.objectStore(uploadStoreName).delete(id);
      tx.oncomplete = () => { db.close(); resolve(); };
      tx.onerror = () => { db.close(); reject(tx.error); };
    });
  }

  async function renameUpload(id, title) {
    const db = await openUploadDb();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(uploadStoreName, 'readwrite');
      const store = tx.objectStore(uploadStoreName);
      const req = store.get(id);
      req.onsuccess = () => { const r = req.result; if (r) store.put({ ...r, title, updatedAt: Date.now() }); };
      tx.oncomplete = () => { db.close(); resolve(); };
      tx.onerror = () => { db.close(); reject(tx.error); };
    });
  }

